generated_oml:
// C3: Physical sensing components
instance SwingAngleEncoder : DTDFVocab:SensingComponent [
    base:desc "Swing‑angle encoder measuring pendulum motion on the gantry crane"
    DTDFVocab:producedData CraneTelemetryStream
]

instance Anemometer : DTDFVocab:SensingComponent [
    base:desc "Anemometer measuring wind speed around the crane"
    DTDFVocab:producedData CraneTelemetryStream
]

// C4: Physical‑to‑virtual interaction (data transmitted)
instance CraneTelemetryStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SwingAngleEncoder, Anemometer
    base:desc "MQTT telemetry stream sent by the Python‑based Physical Crane Interface to the logging application"
]

// C10: Data
instance CraneTelemetryTimeseries : DTDFVocab:Data [
    base:desc "Time‑stamped state logs stored in TimescaleDB"
    DTDFVocab:fromData CraneTelemetryStream
    DTDFVocab:inputTo TimescaleDBEnabler, GrafanaEnabler
]

// C2: Acting components
instance CartStepperMotorActuator : DTDFVocab:ActingComponent [
    base:desc "Cartesian stepper motor driven via Trinamic TMC4671‑Eval controller"
]

instance HoistStepperMotorActuator : DTDFVocab:ActingComponent [
    base:desc "Hoist stepper motor driven via Trinamic TMC4671‑Eval controller"
]

instance ElectromagnetActuator : DTDFVocab:ActingComponent [
    base:desc "Electromagnet at the end of the hoist used to pick up pucks"
]

// C10: Models
instance CADGeometryModel : DTDFVocab:Model [
    base:desc "CAD geometry of the crane (Fusion 360) used for visual reference"
    DTDFVocab:inputTo GrafanaEnabler
]

instance KinematicModel : DTDFVocab:Model [
    base:desc "Kinematic model employed by the Trajectory Generator to compute swing‑free paths"
    DTDFVocab:inputTo PythonGanrailLibEnabler
]

instance SimulationModel : DTDFVocab:Model [
    base:desc "Physics‑based simulation model of the crane and its controllers"
    DTDFVocab:inputTo SimulationEngineEnabler
]

// C11: Enablers
instance TimescaleDBEnabler : DTDFVocab:Enabler [
    base:desc "TimescaleDB instance for time‑series storage (Docker container)"
    DTDFVocab:enables DataLoggingService
]

instance GrafanaEnabler : DTDFVocab:Enabler [
    base:desc "Grafana dashboard visualising telemetry and trajectory traces"
    DTDFVocab:enables DataVisualizationService
]

instance PythonGanrailLibEnabler : DTDFVocab:Enabler [
    base:desc "Python 'gantrylib' module (pip installable) providing trajectory generation and validation logic"
    DTDFVocab:enables TrajectoryGenerationService, ContinuousValidationService
]

instance SimulationEngineEnabler : DTDFVocab:Enabler [
    base:desc "Docker‑ized physics simulation engine used for virtual testing of the crane"
    DTDFVocab:enables PhysicsSimulationService
]

instance HMIApplianceEnabler : DTDFVocab:Enabler [
    base:desc "Human‑Machine Interface component enabling operator interaction through web UI"
    DTDFVocab:enables HumanMachineInterfaceService
]

// C6: Services
instance DataLoggingService : DTDFVocab:Service [
    base:desc "Continuously writes sensor telemetry into TimescaleDB"
    DTDFVocab:provides DataPersistenceInsight, PersistDataAction
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Renders real‑time trajectory traces and telemetry in Grafana"
    DTDFVocab:provides VisualizationInsight, DisplayDashboardAction
]

instance TrajectoryGenerationService : DTDFVocab:Service [
    base:desc "Generates optimal swing‑free trajectories using the kinematic model"
    DTDFVocab:provides OptimalTrajectoryInsight, GenerateTrajectoryAction
]

instance PhysicsSimulationService : DTDFVocab:Service [
    base:desc "Runs physics‑based simulation of crane motions and controller behavior"
    DTDFVocab:provides SimulationResultInsight, RunSimulationAction
]

instance ContinuousValidationService : DTDFVocab:Service [
    base:desc "Compares measured trajectories with simulated ones and raises alerts on deviations"
    DTDFVocab:provides DeviationDetectionInsight, RaiseDeviationAlertAction
]

instance HumanMachineInterfaceService : DTDFVocab:Service [
    base:desc "Provides operator control panel for planning and re‑planning tasks"
    DTDFVocab:provides OperatorControlAction
]

// C17: Insights
instance DataPersistenceInsight : DTDFVocab:Insight [
    base:desc "Confirms that telemetry data are successfully persisted in TimescaleDB"
]

instance VisualizationInsight : DTDFVocab:Insight [
    base:desc "Displays up‑to‑date telemetry and trajectory information in Grafana"
]

instance OptimalTrajectoryInsight : DTDFVocab:Insight [
    base:desc "Identifies the most efficient swing‑free path for the current task"
]

instance SimulationResultInsight : DTDFVocab:Insight [
    base:desc "Provides predicted crane behaviour from the physics simulation"
]

instance DeviationDetectionInsight : DTDFVocab:Insight [
    base:desc "Detects deviations between measured and simulated trajectories using validation metrics"
]

// C17: Actions
instance PersistDataAction : DTDFVocab:Action [
    base:desc "Store incoming telemetry into TimescaleDB"
    DTDFVocab:IsAutomatic true
]

instance DisplayDashboardAction : DTDFVocab:Action [
    base:desc "Refresh Grafana panels with latest telemetry"
    DTDFVocab:IsAutomatic true
]

instance GenerateTrajectoryAction : DTDFVocab:Action [
    base:desc "Compute and output optimal swing‑free trajectory for the crane"
    DTDFVocab:IsAutomatic true
]

instance RunSimulationAction : DTDFVocab:Action [
    base:desc "Execute physics simulation for a given trajectory"
    DTDFVocab:IsAutomatic true
]

instance RaiseDeviationAlertAction : DTDFVocab:Action [
    base:desc "Alert operator when trajectory deviation exceeds threshold"
    DTDFVocab:IsAutomatic false
]

instance OperatorControlAction : DTDFVocab:Action [
    base:desc "Allow operator to modify or re‑plan crane tasks via UI"
    DTDFVocab:IsAutomatic false
]

// C9: Environment (optional grouping)
instance GantryCraneEnvironment : DTDFVocab:Environment [
    base:contains SwingAngleEncoder, Anemometer, CartStepperMotorActuator, HoistStepperMotorActuator, ElectromagnetActuator
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "Digital twin services (e.g., the Trajectory Generator) publish command messages via MQTT; the Physical Crane Interface receives them, the Control Application translates the commands into motor set‑points sent to the Trinamic controllers, thus moving the cart, hoist and actuating the electromagnet."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The twin is orchestrated as a set of Docker‑containerized services (TimescaleDB, MQTT broker, Grafana) together with Python applications (Physical Crane Interface, Control Application, Logging Application, Trajectory Generator, Simulation Service, Continuous Validation Service, Human‑Machine Interface) communicating primarily over MQTT and SQL, all running on a single host PC that is also directly connected to the physical crane."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The digital twin spans the design stage (CAD models of the crane created in Autodesk Fusion 360), the manufacturing/assembly stage (physical frame, motors, sensors), and the operation stage (real‑time sensor data, trajectory execution, and validation)."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Continuous Validation Service continuously compares measured trajectories with simulated counterparts, computes distance metrics, and checks them against a predefined acceptable threshold; violations trigger operator alerts on the Grafana dashboard, providing quantitative fidelity assessment of the kinematic and simulation models."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Data exchange between PT and DT uses MQTT (Eclipse Mosquitto) for command and event signalling, and PostgreSQL/TimescaleDB over standard TCP/IP for time‑series storage; the Python Physical Crane Interface communicates with the Arduino via serial/USB."
]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "All twin services are deployed on a personal computer; the database, MQTT broker and Grafana dashboard are Docker containers started with a provided Docker‑Compose file; the remaining Python modules run natively on the host after installing the 'gantrylib' package."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The exemplar follows several industry‑recognised standards and modeling approaches: C4 Model for architecture description, Capella Arcadia method for system modelling, MQTT (ISO/IEC 20922) as a standard messaging protocol, TimescaleDB built on the PostgreSQL standard, Docker container standards, and CAD data in Autodesk Fusion360 (widely supported format). These standards ensure interoperability and reproducibility of the digital twin components."
]
